import{_ as e,o as a,c as t,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"心之银影","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/心之银影.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/心之银影.md"}'),o={name:"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/心之银影.md"};function d(p,b,l,_,i,c){return a(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"心之银影",tabindex:"-1"},[n("心之银影 "),r("a",{class:"header-anchor",href:"#心之银影","aria-label":'Permalink to "心之银影"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌033")])])],-1),s('<h1 id="心之银影-1" tabindex="-1">心之银影 <a class="header-anchor" href="#心之银影-1" aria-label="Permalink to &quot;心之银影&quot;">​</a></h1><p>心之银影<br> 魔幻本质<br> 描述：心之银影是一把可以单手握持的镀银的西式轻剑，为了讨伐女巫而制作。<br> 【该物品为逐级购买，若无特殊说明，低级特性与高等级特性叠加生效，故高等级不再赘述低级特性】</p><p>D级：制式银剑<br> D+500<br> 描述：“你是为了什么而进的讨伐队？”<br> “哈，找乐子，把自己的命给搭上？”<br> “来吧臭小子，拿上这把剑，我们出发”<br> 武器伤害：8L<br> 体积：3<br> 使用专业：剑<br> 武器类型：轻剑<br> 伤害类型：物理-挥砍<br> 基础属性：【破甲1】<br> 【迅击】：你可以在一次攻击时将武器提供的至多1点【破甲】转化为【高速】使用，如此做时，本轮内使用者的移动速度提升5米<br> 【银】：该武器具有【银】的性质<br> 【瞬魔】：纯粹的银拥有极强的能量传导性质，每回合一次，你用该武器释放的消耗心智类能量的能力减少2点（不能小于1）</p><p>C级：心之钉刺<br> C+1000<br> 描述：“你晕倒了哦”<br> “来讨伐我的吗？可以哦，举起剑吧”<br> “不想吗，拿着这把剑走吧，我给这把剑上了点魔法，应该能帮助你。”<br> 武器伤害：16L<br> 体积：3<br> 使用专业：剑<br> 武器类型：轻剑<br> 伤害类型：物理-挥砍<br> 基础属性：【破甲1】<br> 【心之呼号】：你使用该武器释放的消耗心智类能量的攻击技艺获得【能量武器】特性<br> 【迅捷符文】：你使用该武器时，可以将消耗心智类能量释放的技艺或者攻击结合在移动中进行</p><p>B级：影之守护<br> B+2000<br> 描述：“你说你不想干了，什么意思？”<br> “女巫是不是好人跟我们没什么关系，你不干可以滚”<br> “想搞事，就得做好躺着出去的准备！”<br> 武器伤害：23L<br> 体积：3<br> 使用专业：剑<br> 武器类型：轻剑<br> 伤害类型：物理-挥砍<br> 基础属性：【破甲1】，【湮灭】<br> 【极影】：凭借魔法符文在狭小的空间内旋转，闪动，创造出一敌多的攻击形式，你可以将自身的移动变为C级时空来源的【传送移动】，以该武器释放的攻击技艺带有B级的措手不及，由于魔法符文的本质是通过遁入一个短暂存在的异空间进行传送，因此你同时获得A级免疫异空间的效果。</p><p>A级：心之银影<br> A+4000<br> 描述：“帮我把那边的药材拿过来”<br> “真没想到有人愿意帮我，总之，感谢了”<br> “我给你的剑做了个剑鞘，话说它有名字吗？”<br> “那，要不就叫它，心之银影好了。”<br> 武器伤害：35L+1<br> 体积：3<br> 使用专业：剑<br> 武器类型：轻剑<br> 伤害类型：物理-挥砍<br> 基础属性：【破甲】1，【湮灭】<br> 【心之影】：心灵的影子化为前行的证明，【极影】中的措手不及效果现在提升为A级。每轮一次，在你受到一次针对你的单体伤害或攻击时，你可以选择以剑破开空间，闪避至影之空间以此躲开攻击，并在下一瞬回到原位，这是一个A级别时空来源的无敌效果。<br> 【扪心自问】：少年将自己阻挡讨伐的决心灌注于剑上，化为对敌人的质问，以该武器释放的攻击技艺或攻击现在无视对方的盔甲防御，这是一个A级别影响心灵来源的效果，且附带等量的心灵来源的精神束缚，意志豁免。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',8)])])}const m=e(o,[["render",d]]);export{f as __pageData,m as default};
